     1	const GOLD_MINIMUM_CENTS = 10_000;
     2	
     3	export function calculateDiscount({ tier, subtotalCents, coupon = null }) {
     4	  if (coupon === "NO_DISCOUNT") return 0;
     5	  if (tier !== "gold") return 0;
     6	  if (!Number.isInteger(subtotalCents) || subtotalCents < 0) {
     7	    throw new TypeError("subtotalCents must be a non-negative integer");
     8	  }
     9	
    10	  return subtotalCents > GOLD_MINIMUM_CENTS
    11	    ? Math.round(subtotalCents * 0.1)
    12	    : 0;
    13	}
